using UnityEngine;

/// <summary>
/// Reage à compra do Jukebox na loja (ShopUI.OnItemPurchased) e executa o
/// fluxo de primeira vez:
/// 1. Abre o menu do Jukebox automaticamente.
/// 2. Exibe uma mensagem de tutorial (TutorialMessageType.Importante) explicando
///    o que é o Jukebox.
/// 3. Após o player confirmar o tutorial, fecha o menu e o fluxo de compra
///    continua normalmente.
///
/// Montagem no Editor:
/// - Colocar este componente na cena de gameplay (ou num GameObject persistente).
/// - "jukeboxItem": o mesmo ItemData configurado em JukeboxSectionUI.
/// - "jukeboxSectionUI": referência ao painel do Jukebox no menu.
/// - "tutorialText": texto exibido na mensagem de tutorial da 1ª compra.
/// - "tutorialImage" (opcional): imagem exibida acima do texto (tipo Importante).
/// </summary>
public class JukeboxShopHandler : MonoBehaviour
{
    [Header("Referências")]
    [Tooltip("ItemData do Jukebox (mesmo que JukeboxSectionUI.jukeboxItem).")]
    [SerializeField] private ItemData jukeboxItem;

    [Tooltip("Painel/secção do Jukebox no menu de pausa (JukeboxSectionUI).")]
    [SerializeField] private JukeboxSectionUI jukeboxSectionUI;

    [Header("Tutorial da Primeira Compra")]
    [TextArea(3, 8)]
    [Tooltip("Texto da mensagem de tutorial exibida ao comprar o Jukebox pela primeira vez.")]
    [SerializeField] private string tutorialText =
        "Jukebox desbloqueado!\n\nAqui podes ouvir as músicas do jogo a qualquer momento.\n" +
        "Encontra Melodias Selvagens pelo mundo para adicionar novas faixas!";

    [Tooltip("Imagem exibida acima do texto do tutorial (opcional).")]
    [SerializeField] private Sprite tutorialImage;

    private void OnEnable()
    {
        ShopUI.OnItemPurchased += HandleItemPurchased;
    }

    private void OnDisable()
    {
        ShopUI.OnItemPurchased -= HandleItemPurchased;
    }

    private void HandleItemPurchased(ItemData item)
    {
        if (jukeboxItem == null || item == null) return;
        if (item.itemId != jukeboxItem.itemId) return;

        // Só actua na PRIMEIRA compra (onlyBuyOnce + savedAsCollected garantem
        // que só dispara uma vez — mas verificamos por segurança).
        // O ShopUI já marcou o item como collectedSpecialItem antes de disparar
        // este evento, portanto HasCollectedSpecialItem já devolve true aqui.

        // Abre o menu do Jukebox automaticamente.
        if (jukeboxSectionUI != null)
            jukeboxSectionUI.Open();

        // Exibe a mensagem de tutorial (tipo Importante, pausa o jogo).
        TutorialMessageManager.Instance?.ShowImportant(
            tutorialText,
            tutorialImage,
            onConfirmed: () =>
            {
                // Fecha o menu do Jukebox após o player confirmar o tutorial.
                if (jukeboxSectionUI != null)
                    jukeboxSectionUI.Close();
            }
        );
    }
}
